#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
long long n,a[N],x[N],k[21][2],sum;
long long power(long long p){//2^p
    long long as=1;
    while(p--)as*=2;
    return as;
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){cin>>a[i];x[i]=x[i-1]^a[i];}
    //for(int i=1;i<=n;i++)cout<<x[i]<<" ";
    //cout<<endl<<endl<<endl;
    for(int i=0;i<=n;i++)
        for(int j=0;j<=20;j++)k[j][(x[i]>>j)%2]++;
    //for(int i=0;i<=20;i++)cout<<k[i][0]<<" "<<k[i][1]<<endl;
    //cout<<endl<<endl;
    for(int i=0;i<=20;i++)sum+=k[i][0]*k[i][1]*power(i);
    cout<<sum;
    return 0;
}
/*
首先做了个 60 分（可以说是用的前缀异或和）。

然后想 100 分解法……
想到了双指针，但好像不知道怎么用；
想到了二分（O(n log n)能过），但感觉这纯粹是凑时间，根本不知道二分什么；
想到了排序（sort），但排了序又有什么用呢？去二分？胡说八道！

我的提问：
1.用什么算法？双指针？二分？排序？还是别的？
2.时间是多少？
3.具体怎么实现？

————————————————看第一篇题解————————————————

疑问得到解答：
1.不好概括，主要是运用了异或的特点：二进制位不同则为 1，相同则为 0。
2.时间复杂度 O(n*21)，可以。
3.先用一个数组 k_i,j 表示二进制第 i 位为 j 的个数；
  再全部遍历一遍，求出每个 k_i,0 * k_i,1 * 2^i（2 的 i 次方，不是 2 异或 i）并加起来即可。

来编代码吧！
